FUNCTION_BLOCK StackMin
VAR_INPUT
push : BOOL;
pop : BOOL;
reset : BOOL;
END_VAR
VAR_OUTPUT
error : BOOL;
status : WORD;
END_VAR
VAR_IN_OUT
item : INT;
stack : ARRAY[0..3] OF INT;
END_VAR
VAR
top : INT := -1;
i : INT;
minIndex : INT;
minValue : INT;
END_VAR

error := FALSE;
status := 16#0000;

IF reset THEN
    top := -1;
ELSIF push THEN
    IF top = 3 THEN
        error := TRUE;
        status := 16#8A04;
    ELSE
        top := top + 1;
        stack[top] := item;
        error := FALSE;
        status := 16#0000;
    END_IF;
ELSIF pop THEN
    IF top = -1 THEN
        error := TRUE;
        status := 16#8A05;
    ELSE
        minValue := stack[0];
        minIndex := 0;

        FOR i := 1 TO top DO
            IF stack[i] < minValue THEN
                minValue := stack[i];
                minIndex := i;
            END_IF;
        END_FOR;

        item := minValue;

        FOR i := minIndex TO top - 1 DO
            stack[i] := stack[i + 1];
        END_FOR;

        top := top - 1;
        error := FALSE;
        status := 16#0000;
    END_IF;
END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK FloatingAverage
VAR_INPUT
    cyclicExecution : BOOL;
    trigger : BOOL;
    value : REAL;
    windowSize : INT;
    reset : BOOL;
END_VAR
VAR_OUTPUT
    average : REAL;
    windowSizeReached : BOOL;
    error : BOOL;
    status : WORD;
END_VAR
VAR
    dataBuffer : ARRAY[1..100] OF REAL;
    bufferIndex : INT := 1;
    sum : REAL := REAL(0.0);
    prevTrigger : BOOL;
    currentCount : INT;
END_VAR

IF reset = TRUE THEN
    bufferIndex := 1;
    sum := REAL(0.0);
    FOR i := 1 TO 100 DO
        dataBuffer[i] := REAL(0.0);
    END_FOR;
END_IF

IF windowSize < 1 OR windowSize > 100 THEN
    error := TRUE;
    status := 16#8200;
    average := 0.0;
    windowSizeReached := FALSE;
ELSE
    error := FALSE;
    status := 16#0000;

    IF cyclicExecution = TRUE OR (trigger = TRUE AND prevTrigger = FALSE) THEN
        IF bufferIndex > windowSize THEN
            bufferIndex := bufferIndex - 1;
        END_IF;

        dataBuffer[bufferIndex] := value;
        sum := sum + value;
        bufferIndex := bufferIndex + 1;

        IF bufferIndex > windowSize THEN
            windowSizeReached := TRUE;
        ELSE
            windowSizeReached := FALSE;
        END_IF;
    END_IF;

    IF windowSizeReached = TRUE THEN
        average := sum / REAL(windowSize);
    ELSE
        currentCount := bufferIndex - 1;
        IF currentCount > 0 THEN
            average := sum / REAL(currentCount);
        ELSE
            average := 0.0;
        END_IF;
    END_IF;
END_IF;

prevTrigger := trigger;

END_FUNCTION_BLOCK

