FUNCTION_BLOCK TruckGarage
VAR_INPUT
enter_flag : BOOL;
exit_flag : BOOL;
VehicleNumber_in : INT;
END_VAR
VAR_OUTPUT
truck : T_TRUCK_INFO;
END_VAR
VAR_IN_OUT
