                            TaskAssigned := TRUE;
                            EXIT; // Changed Break to EXIT
                        END_IF;
                    END_FOR;
                END_IF;
            END_IF;
            If TaskAssigned = TRUE Then
                EXIT;
            END_IF;
        END_FOR;
    END_IF;

    For i := 1 To 3 Do
        MinPos := 0;
        If AGVPosition[i] < MinPos Then
            MinPos := AGVPosition[i];
        END_IF;
        If MinPos < 0 Then
            AGVPosition[i] := 0;
        END_IF;
    END_FOR;

    For i := 1 To 3 Do
        If AGVPosition[i] = 0 Then
            If i = 1 Then
                AGV1_Ready := TRUE;
            ELSIF i = 2 Then
                AGV2_Ready := TRUE;
            ELSE
                AGV3_Ready := TRUE;
            END_IF;
        END_IF;
